-- Update black case no by account_no
-- Source: 2 pasted columns supplied by user
-- Rows: 2792
-- Assumption: table = customers, column to update = black_case_no
-- If your actual column name is different, replace black_case_no before running.

BEGIN TRANSACTION;

DROP TABLE IF EXISTS _tmp_customer_black_case_update;
CREATE TEMP TABLE _tmp_customer_black_case_update (
    account_no TEXT PRIMARY KEY,
    black_case_no TEXT NOT NULL
);








-- Check how many input account_no values exist in customers before updating
SELECT COUNT(*) AS matched_rows
FROM customers c
JOIN _tmp_customer_black_case_update m ON m.account_no = c.account_no;

-- Update customers.black_case_no from mapping table
UPDATE customers
SET black_case_no = (
    SELECT m.black_case_no
    FROM _tmp_customer_black_case_update m
    WHERE m.account_no = customers.account_no
)
WHERE account_no IN (SELECT account_no FROM _tmp_customer_black_case_update);

-- Review any account_no in the input list that was not found in customers
SELECT m.account_no, m.black_case_no AS intended_black_case_no
FROM _tmp_customer_black_case_update m
LEFT JOIN customers c ON c.account_no = m.account_no
WHERE c.account_no IS NULL
ORDER BY m.account_no;

DROP TABLE IF EXISTS _tmp_customer_black_case_update;

COMMIT;
